package org.apache.commons.compress.archivers.tar;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.compress.archivers.tar.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
    // This is the Cucumber test runner class
}

package org.apache.commons.compress.archivers.tar;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.ArchiveEntry;
import org.apache.commons.compress.archivers.tar.TarArchiveInputStream;

import java.io.ByteArrayInputStream;
import java.io.IOException;

import static org.junit.Assert.*;

public class StepDefs {

    private TarArchiveInputStream tarInputStream;
    private ArchiveEntry nextEntry;
    private Exception thrownException;

    // Create a mock TAR data that has blank lines in PAX header
    // This creates a simple tar structure with PAX headers that contain blank lines
    private byte[] createTarWithPaxHeaderWithBlankLine() {
        // This represents a very simplified PAX header record with a blank line
        // The actual structure will have the PAX header format

        // Creating a simple tar entry with PAX header containing a blank line
        // Format: length (in octal) + space + key=value + blank line
        String paxHeaderContent = "20path=example.txt\n\n"; // blank line between records
        String regularEntry = "13usr/1234567890 0000000 0000000 00000644 00000000000 01234567 x  example.txt";

        byte[] paxBytes = paxHeaderContent.getBytes();
        byte[] regularBytes = regularEntry.getBytes();

        // Calculate the size and align to 512-byte blocks
        int paxSize = paxBytes.length;
        int regularSize = regularBytes.length;

        // We'll create a simple byte array that simulates the problematic TAR with blank lines
        // For this test, we'll create a minimal tar with a PAX header containing a blank line
        byte[] data = new byte[paxSize + regularSize];
        System.arraycopy(paxBytes, 0, data, 0, paxSize);
        System.arraycopy(regularBytes, 0, data, paxSize, regularSize);

        return data;
    }

    @Given("a TAR archive input stream")
    public void a_tar_archive_input_stream() {
        byte[] tarData = createTarWithPaxHeaderWithBlankLine();
        tarInputStream = new TarArchiveInputStream(new ByteArrayInputStream(tarData));
    }

    @And("the archive contains a PAX header entry")
    public void the_archive_contains_a_pax_header_entry() {
        // This is already handled in the previous step
    }

    @And("the PAX header data contains a blank line \\(a single newline character\\) between records")
    public void the_pax_header_data_contains_a_blank_line_between_records() {
        // This is also already handled by creating the tar data
    }

    @When("I call getNextTarEntry")
    public void i_call_get_next_tar_entry() {
        try {
            nextEntry = tarInputStream.getNextTarEntry();
        } catch (IOException e) {
            thrownException = e;
        }
    }

    @Then("the blank line should be ignored")
    public void the_blank_line_should_be_ignored() {
        // This is verified by the absence of exception
        if (thrownException != null) {
            fail("Exception was thrown: " + thrownException.getMessage());
        }
    }

    @Then("the next TAR entry should be successfully retrieved")
    public void the_next_tar_entry_should_be_successfully_retrieved() {
        assertNotNull("Next entry should not be null", nextEntry);
    }

    @Then("no NegativeArraySizeException should be thrown")
    public void no_negative_array_size_exception_should_be_thrown() {
        if (thrownException instanceof NegativeArraySizeException) {
            fail("NegativeArraySizeException was thrown: " + thrownException.getMessage());
        }
    }
}

